import { existsSync, readFileSync } from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';
import { describe, expect, runPactVerification, test } from '@a0n/gnosis/test';

const workspaceRoot = fileURLToPath(new URL('../../../..', import.meta.url));
const registryPath = path.join(workspaceRoot, '.aeon/pact-registry.json');

describe('Gnosis Pact runner', () => {
  test('wraps Pact verification in the unified file model', async () => {
    const result = await runPactVerification({
      workspaceRoot,
      grep: 'rejection-record-forge',
    });

    expect(result.file?.kind).toBe('pact');
    expect(result.file?.entries.length ?? 0).toBeGreaterThan(0);
    expect(result.file?.ok).toBe(true);
  });

  test('plain verification does not rewrite the tracked registry', async () => {
    const before = existsSync(registryPath)
      ? readFileSync(registryPath, 'utf8')
      : null;

    await runPactVerification({
      workspaceRoot,
      grep: 'rejection-record-forge',
    });

    const after = existsSync(registryPath)
      ? readFileSync(registryPath, 'utf8')
      : null;
    expect(after).toBe(before);
  });
});
